mapper.select:
SELECT u.id AS userId, u.username AS username, u.nickname AS nickname, u.avatar AS avatar, sc.id AS chapterId, sc.title AS chapterTitle, s.name AS skillName, ucp.score AS score, ucp.update_time AS updateTime FROM user_chapter_progress ucp JOIN sys_user u ON ucp.user_id = u.id JOIN skill_chapter sc ON ucp.chapter_id = sc.id JOIN skill s ON sc.skill_id = s.id WHERE ucp.status = 'COMPLETED'
AND ucp.user_id = #{userId}
ORDER BY ucp.update_time DESC
